from abc import ABC, abstractmethod

class AbstractionPayment(ABC):
    def __init__(self, id, amount, currency):
        self.id = id
        self.amount = amount
        self.currency = currency

    @abstractmethod
    def process_payment(self):
        pass

    @abstractmethod
    def validate_payment(self):
        pass

class CardPayment(AbstractionPayment):
    def process_payment(self):
        print(f"Processing card payment for {self.amount} {self.currency}")

    def validate_payment(self):
        print(f"Validating card payment for {self.amount} {self.currency}")

class MobilePayment(AbstractionPayment):
    def process_payment(self):
        print(f"Processing mobile payment for {self.amount} {self.currency}")

    def validate_payment(self):
        print(f"Validating mobile payment for {self.amount} {self.currency}")

def default_test():
    card_payment = CardPayment(1, 100, "USD")
    card_payment.process_payment()
    card_payment.validate_payment()

    mobile_payment = MobilePayment(2, 150, "EUR")
    mobile_payment.process_payment()
    mobile_payment.validate_payment()
